    int q = p + 1;
    while (q < n && nums[q] < nums[q - 1]) {
        q++;
    }

    if (q == n) return false;

    // Check if the remaining part is strictly increasing
    for (int i = q; i < n; i++) {
        if (nums[i] <= nums[i - 1]) {
            return false;
        }
    }

    return true;
}
